import{_ as i,o as l,c as o,a0 as t}from"./chunks/framework.Cyxxdjdf.js";const h=JSON.parse('{"title":"工程之道","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"contents/engineering-philosophy.md","filePath":"contents/engineering-philosophy.md"}'),a={name:"contents/engineering-philosophy.md"};function c(s,e,d,n,p,r){return l(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="工程之道" tabindex="-1">工程之道 <a class="header-anchor" href="#工程之道" aria-label="Permalink to &quot;工程之道&quot;">​</a></h1><div style="display:flex;justify-content:center;"><img src="/learning-resources_dt.svg" style="height:300px;" alt="learning"></div><h2 id="现象" tabindex="-1">现象 <a class="header-anchor" href="#现象" aria-label="Permalink to &quot;现象&quot;">​</a></h2><p>在实际工程中，很多项目最终走向大规模重构，甚至推倒重来。</p><p>原因往往不是技术选型错误。</p><p>而是在长期迭代过程中，混乱不断累积，最终达到不重构就无法继续演进的程度。</p><div class="danger custom-block"><p class="custom-block-title">工程混乱</p><ul><li>主页 <code>ViewModel</code> 等核心类沦为万能容器，堆积跨界面业务，代码野蛮膨胀至数千行。</li><li>核心业务方法动辄好几百行，充斥着流水账式的逻辑堆砌，缺乏函数抽象，改动犹如乱麻引线。</li><li>单个 XML 布局突破两千行且深层嵌套，渲染性能劣化，导致界面重构与复用完全瘫痪。</li><li>泛滥使用 <code>LiveData</code>，多处改动同一数据源、观察者散落各处，甚至在回调中层层嵌套触发其他数据源，导致数据流向沦为彻底不可逆向溯源的黑洞。</li><li>缺乏统一数据层抽象，接口响应与原始解析无序混在业务层，动一发而引全身。</li><li>随手 <code>new Thread</code> 或无节制滥用全局线程池，导致内存泄漏、死锁与任务断流频发。</li><li>变量与常量充斥着 <code>a</code>、<code>temp</code>、<code>it1</code>、<code>it2</code>、<code>data1</code> 等无意义符号。如不费神摸索，几乎无法理解用途。</li><li>控制流层层嵌套，<code>if</code> 套 <code>if</code>，<code>switch</code> 套 <code>if</code>，改一个逻辑先滚半天滚动条，搞得眼花缭乱。</li><li>模块间通过强引用跨界绑定，缺乏接口隔离，追踪一个功能需要点开十几个模块的文件。</li><li>相同逻辑多处复制粘贴，修改一个 Bug 需要全工程搜索，漏改一个即成线上隐患。</li><li>分支管理缺乏规范，<code>feature</code>、<code>release</code>、<code>hotfix</code> 混在一起，甚至根本就没有这些分支，版本状态无人说得清。</li></ul></div><h2 id="后果" tabindex="-1">后果 <a class="header-anchor" href="#后果" aria-label="Permalink to &quot;后果&quot;">​</a></h2><p>这些代码通常都能运行，甚至已经在线上稳定运行了很久。</p><p>但是，真正的危机往往在变更发生的那一刻瞬间爆发！</p><div class="warning custom-block"><p class="custom-block-title">修改一个功能</p><p>需要先阅读几百行甚至上千行毫无章法的历史代码。</p><p>很多时间并没有花在编写核心业务上，</p><p>而是花在寻找入口、理解历史逻辑和确认影响范围上。</p></div><div class="danger custom-block"><p class="custom-block-title">修复一个 Bug</p><p>由于职责混乱、耦合严重，无法快速、精准地评估改动的影响范围。</p><p>在线上修复一个 Bug，极易引发难以预料的级联崩溃。</p><p>最终形成：修一个 Bug -&gt; 带出两个 Bug -&gt; 再修两个 Bug，简直改之不尽 ！</p></div><div class="warning custom-block"><p class="custom-block-title">新增一个需求</p><p>历史代码之间已形成了大量脆弱的隐式依赖，</p><p>导致改动一个看似独立的边缘模块，却能在蝴蝶效应下，直接击穿完全不相关的核心业务线。</p></div><h2 id="代价" tabindex="-1">代价 <a class="header-anchor" href="#代价" aria-label="Permalink to &quot;代价&quot;">​</a></h2><p>混乱带来的成本不会一次性显现，而是潜伏在每一次需求变更与线上故障中，并加速项目走向不可逆的 “技术债崩盘”。</p><div class="warning custom-block"><p class="custom-block-title">项目劣化指标</p><ul><li>新功能开发越来越慢，交付速度呈断崖式下跌。</li><li>Bug 数量越来越多，线上故障率居高不下。</li><li>任何微小的改动都可能演变为高风险的 “排雷” 行动，开发人员开始害怕并避免修改历史代码。</li><li>代码彻底天书化，新成员接手时面临极高的认知成本与劝退率。</li></ul><p>这一切，皆是混乱吞噬工程秩序的必然结果。</p><div class="danger custom-block"><p class="custom-block-title">项目最危险的状态也就此来临，不是运行不了，而是虽然还能运行，却已经没人愿意主动继续维护。</p></div></div><h2 id="目的" tabindex="-1">目的 <a class="header-anchor" href="#目的" aria-label="Permalink to &quot;目的&quot;">​</a></h2><p>规范无法消灭复杂度，但可以阻止复杂度走向失控。</p><p>引入本套工程规范的核心目的，就是给项目建立一道防线，让混乱不要轻易蔓延。</p><div class="tip custom-block"><p class="custom-block-title">规范落地的核心铁律</p><ul><li><strong>可读性优先</strong>：今天写下的每一行代码，未来都需要有人阅读，必须降低后人的认知成本。</li><li><strong>设计留白</strong>：今天做出的每一个关键设计，未来可能要被扩展，必须保持接口的弹性。</li><li><strong>不留技术债</strong>：今天为了赶进度留下的每一个临时补丁，未来都需要有人加倍偿还，必须杜绝短视的特例代码</li><li><strong>知识内聚</strong>：所有的奇葩 Bug 修复、特殊的兼容逻辑，必须沉淀到关键行注释或文档中。</li></ul></div><h2 id="结尾" tabindex="-1">结尾 <a class="header-anchor" href="#结尾" aria-label="Permalink to &quot;结尾&quot;">​</a></h2><div style="display:flex;justify-content:center;"><img src="/launch-app.svg" style="height:400px;" alt="launch-app"></div><p>本开发规范不讨论某种具体技术是否足够先进，也不争辩某种架构是否绝对正确。</p><p>因为技术会更新，框架会迭代，工具会淘汰。</p><p><strong>但混乱带来的代价始终存在。</strong></p><p>因此，这里只关注一件事情：<strong>如何减少混乱，建立秩序。</strong></p>',26)])])}const g=i(a,[["render",c]]);export{h as __pageData,g as default};
